def test_run_codex_uses_isolated_codex_home(
    supervisor_module: object,
    repo_fixture: Path,
    monkeypatch: pytest.MonkeyPatch,
) -> None:
    class FakeProcess:
        def __init__(self) -> None:
            self.stdout = io.StringIO("")
            self.stderr = io.StringIO("")
            self.wait_timeout: float | None = None

        def wait(self, timeout: float | None = None) -> int:
            self.wait_timeout = timeout
            return 0

    captured: dict[str, object] = {}

    def fake_create_child_codex_home(
        *,
        source_codex_home: Path = Path(),
        profile: object | None = None,
        bypass_inner_sandbox: bool = False,
    ) -> Path:
        _ = source_codex_home
        captured["profile"] = profile
        captured["bypass_inner_sandbox"] = bypass_inner_sandbox
        child_home = repo_fixture / ".fake-codex-home"
        child_home.mkdir(exist_ok=True)
        return child_home

    def fake_popen(
        cmd: list[str],
        *,
        cwd: Path,
        env: dict[str, str],
        stdout: object,
        stderr: object,
        text: bool,
        bufsize: int,
    ) -> FakeProcess:
        captured["cmd"] = cmd
        captured["cwd"] = cwd
        captured["env"] = env
        captured["stdout"] = stdout
        captured["stderr"] = stderr
        captured["text"] = text
        captured["bufsize"] = bufsize
        process = FakeProcess()
        captured["process"] = process
        return process

