def test_economic_observability_metrics_keep_proxy_semantics_with_active_prices(
    supervisor_module: object,
) -> None:
    signals = supervisor_module.build_economic_observability_metric_signals(
        model_usage_telemetry={
            "model_usage_surfaces": [
                {
                    "telemetry_status": "usage_proxy_available",
                    "usage_proxy": {"value": 2},
                    "observed_run_ids": ["run-2", "run-1"],
                }
            ]
        },
        pricing_provenance={"pricing_surfaces": [{"price_status": "active_price_source"}]},
        review_feedback_index={
            "entries": [{"verification": ["targeted_test", "targeted_test", "manual_review"]}]
        },
    )

    by_id = {entry["metric_id"]: entry for entry in signals}
    node_cost = by_id["node_inference_cost"]
    assert node_cost["value"] == 2
    assert node_cost["value_kind"] == "usage_proxy_not_monetary_cost"
    assert node_cost["price_status"] == "active_price_source"
    assert "proxy activity unit" in node_cost["basis"]
    assert "price_status remains missing_price_source" not in node_cost["basis"]

    verification_cost = by_id["verification_cost"]
    assert verification_cost["input_summary"]["verification_kind_counts"] == {
        "manual_review": 1,
        "targeted_test": 2,
    }


def test_sib_full_defect_balance_requires_feedback_evidence(
    supervisor_module: object,
) -> None:
    base_kwargs = {
        "specs": supervisor_module.load_specs(),
        "specification_verifiability": {"score": 0.5},
        "sib_entry": {"score": 0.7},
        "implementation_work_index": {"entries": [{"required_tests": ["test_acceptance"]}]},
    }

    missing_feedback = supervisor_module.build_sib_full_proxy_metric_signals(
        **base_kwargs,
        review_feedback_index={"entries": []},
    )
    missing_by_id = {entry["metric_id"]: entry for entry in missing_feedback}
    assert missing_by_id["sib_eff_star"]["status"] == "observed_proxy"
    assert missing_by_id["defect_balance_at_root"]["status"] == "not_observed"
    assert missing_by_id["defect_balance_at_root"]["value"] is None

    observed_feedback = supervisor_module.build_sib_full_proxy_metric_signals(
        **base_kwargs,
        review_feedback_index={
            "entries": [
                {"root_cause_class": None},
                {"root_cause_class": "test_coverage_gap"},
            ]
        },
    )
    observed_by_id = {entry["metric_id"]: entry for entry in observed_feedback}
    defect_balance = observed_by_id["defect_balance_at_root"]
    assert defect_balance["status"] == "observed_proxy"
    assert defect_balance["value"] == 0.7
    assert defect_balance["input_summary"]["root_cause_class_counts"] == {
        "test_coverage_gap": 1,
        "unclassified": 1,
    }


